#Classe che gestione del display
class OledDisplayManager:
    def __init__(self, width=128, height=64, scl_pin=22, sda_pin=21):
        self.width = width
        self.height = height
        self.i2c = I2C(0, scl=Pin(scl_pin), sda=Pin(sda_pin))
        self.display = ssd1306.SSD1306_I2C(width, height, self.i2c)

    def clear(self):
        self.display.fill(0)
        self.display.show()

    def show_image(self, image_bytes):
        try:
            fb = framebuf.FrameBuffer(image_bytes, self.width, self.height, framebuf.MONO_HLSB)
            self.clear()
            self.display.blit(fb, 0, 0)
            self.display.show()
        except Exception as e:
            print("Errore nella visualizzazione dell'immagine:", e)
    
    def show_text(self, text, x=0, y=0):
        self.clear()
        self.display.text(text, x, y)
        self.display.show()

